import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Separator.module.css';

export type SeparatorOrientation = 'horizontal' | 'vertical';
export type SeparatorSize = 'xs' | 'sm' | 'md' | 'lg';
export type SeparatorVariant = 'solid' | 'dashed' | 'dotted';

export type SeparatorRootProps = HTMLArkProps<'span'> & {
  orientation?: SeparatorOrientation;
  size?: SeparatorSize;
  variant?: SeparatorVariant;
};

const SeparatorRoot = forwardRef<HTMLSpanElement, SeparatorRootProps>(function SeparatorRoot(
  {
    asChild,
    className,
    orientation = 'horizontal',
    role,
    size = 'sm',
    variant = 'solid',
    'aria-orientation': ariaOrientation,
    ...props
  },
  ref,
) {
  const resolvedRole = role ?? 'separator';

  return (
    <ark.span
      ref={ref}
      asChild={asChild}
      role={resolvedRole}
      aria-orientation={ariaOrientation ?? (resolvedRole === 'separator' ? orientation : undefined)}
      data-scope="separator"
      data-part="root"
      data-slot="separator-root"
      data-orientation={orientation}
      data-size={size}
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const Separator = Object.assign(SeparatorRoot, {
  Root: SeparatorRoot,
});

export { Separator };

@layer ui.components {
  .root {
    display: block;
    flex-shrink: 0;
    border: 0;
    border-color: var(--separator-color, var(--color-border));
    border-style: var(--separator-border-style, solid);

    &[data-scope='separator'][data-part='root'][data-size='xs'] {
      --separator-size-thickness: 0.5px;
    }

    &[data-scope='separator'][data-part='root'][data-size='sm'] {
      --separator-size-thickness: 1px;
    }

    &[data-scope='separator'][data-part='root'][data-size='md'] {
      --separator-size-thickness: 2px;
    }

    &[data-scope='separator'][data-part='root'][data-size='lg'] {
      --separator-size-thickness: 3px;
    }

    &[data-scope='separator'][data-part='root'][data-variant='dashed'] {
      --separator-border-style: dashed;
    }

    &[data-scope='separator'][data-part='root'][data-variant='dotted'] {
      --separator-border-style: dotted;
    }

    &[data-orientation='horizontal'] {
      width: var(--separator-length-horizontal, 100%);
      height: 0;
      border-block-start-width: var(--separator-thickness, var(--separator-size-thickness, 1px));
    }

    &[data-orientation='vertical'] {
      width: 0;
      height: var(--separator-length-vertical, 1em);
      border-inline-start-width: var(--separator-thickness, var(--separator-size-thickness, 1px));
    }
  }
}

export { Separator } from './Separator';
export type {
  SeparatorOrientation,
  SeparatorRootProps,
  SeparatorSize,
  SeparatorVariant,
} from './Separator';
